import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Input, Select, icon } from 'decantr/components';

code.example:
function InviteForm({ onInvite, onClose, suggestions = [] }) {
  const { div, span, h2, label } = tags;
  const [email, setEmail] = createSignal('');
  const [role, setRole] = createSignal('editor');
  const [showSuggestions, setShowSuggestions] = createSignal(false);

  const roles = [
    { value: 'viewer', label: 'Can view' },
    { value: 'commenter', label: 'Can comment' },
    { value: 'editor', label: 'Can edit' },
    { value: 'admin', label: 'Full access' }
  ];

  const handleSubmit = () => {
    if (email().includes('@')) {
      onInvite({ email: email(), role: role() });
      setEmail('');
    }
  };

  const filteredSuggestions = suggestions.filter(s => 
    s.email.toLowerCase().includes(email().toLowerCase()) ||
    s.name.toLowerCase().includes(email().toLowerCase())
  ).slice(0, 5);

  return div({ class: css('_flex _col _gap4') },
    // Header
    div({ class: css('_flex _aic _jcsb') },
      h2({ class: css('_heading4') }, 'Share document'),
      Button({ variant: 'ghost', size: 'sm', onclick: onClose }, icon('x'))
    ),
    // Invite form
    div({ class: css('_flex _col _gap2') },
      label({ class: css('_textsm _fontmedium') }, 'Invite people'),
      div({ class: css('_flex _gap2') },
        div({ class: css('_flex1 _relative') },
          Input({
            type: 'email',
            placeholder: 'Email address',
            value: email(),
            onInput: (e) => { setEmail(e.target.value); setShowSuggestions(true); },
            onFocus: () => setShowSuggestions(true),
            onBlur: () => setTimeout(() => setShowSuggestions(false), 200)
          }),
          // Autocomplete suggestions
          showSuggestions() && filteredSuggestions.length > 0 ? div({
            class: css('_absolute _top[100%] _left0 _wfull _bg[var(--surface)] _shadow _r1 _border _mt1 _z[10]')
          },
            ...filteredSuggestions.map(s => div({
              class: css('_flex _aic _gap2 _p2 _cursor[pointer] _hover:bg[var(--surface-raised)]'),
              onclick: () => { setEmail(s.email); setShowSuggestions(false); }
            },
              Avatar({ src: s.avatar, fallback: s.initials, size: 'sm' }),
              div({ class: css('_flex _col') },
                span({ class: css('_textsm _fontmedium') }, s.name),
                span({ class: css('_textxs _fgmuted') }, s.email)
              )
            ))
          ) : null
        ),
        Select({
          value: role(),
          onChange: (e) => setRole(e.target.value),
          options: roles,
          class: css('_w[140px]')
        }),
        Button({ onclick: handleSubmit, disabled: !email().includes('@') }, 'Invite')
      )
    )
  );
}

