function LinkSharing({ shareLink, linkEnabled, linkPermission, onToggle, onPermissionChange }) {
  const { div, span, label } = tags;
  const [copied, setCopied] = createSignal(false);

  const copyLink = () => {
    navigator.clipboard.writeText(shareLink);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const permissions = [
    { value: 'view', label: 'Anyone with link can view' },
    { value: 'comment', label: 'Anyone with link can comment' },
    { value: 'edit', label: 'Anyone with link can edit' }
  ];

  return div({ class: css('_flex _col _gap4') },
    // Toggle
    div({ class: css('_flex _aic _jcsb') },
      div({ class: css('_flex _col') },
        span({ class: css('_textsm _fontmedium') }, 'Share with link'),
        span({ class: css('_textxs _fgmuted') }, 'Anyone with the link can access')
      ),
      Button({
        variant: linkEnabled ? 'default' : 'outline',
        size: 'sm',
        onclick: onToggle
      }, linkEnabled ? 'Enabled' : 'Disabled')
    ),
    // Link and permissions
    linkEnabled ? div({ class: css('_flex _col _gap3') },
      // Copy link
      div({ class: css('_flex _gap2') },
        Input({
          type: 'text',
          value: shareLink,
          readOnly: true,
          class: css('_flex1 _bg[var(--surface-raised)]')
        }),
        Button({ variant: 'outline', onclick: copyLink },
          icon(copied() ? 'check' : 'copy', { size: '14' }),
          copied() ? ' Copied!' : ' Copy'
        )
      ),
      // Permission level
      Select({
        value: linkPermission,
        onChange: (e) => onPermissionChange(e.target.value),
        options: permissions
      })
    ) : null
  );
}

