function MembersList({ members, pending, currentUserId, onRoleChange, onRemove, onCancelInvite }) {
  const { div, span } = tags;

  const roles = [
    { value: 'viewer', label: 'Viewer' },
    { value: 'commenter', label: 'Commenter' },
    { value: 'editor', label: 'Editor' },
    { value: 'admin', label: 'Admin' }
  ];

  return div({ class: css('_flex _col _gap4') },
    // Current members
    div({ class: css('_flex _col _gap2') },
      span({ class: css('_textsm _fontmedium _fgmuted') }, 'Members'),
      ...members.map(member =>
        div({ class: css('_flex _aic _gap3 _py2') },
          Avatar({ src: member.avatar, fallback: member.initials, size: 'sm' }),
          div({ class: css('_flex _col _flex1') },
            span({ class: css('_textsm _fontmedium') }, member.name),
            span({ class: css('_textxs _fgmuted') }, member.email)
          ),
          member.id === currentUserId ? span({ class: css('_textxs _fgmuted') }, 'You') :
            div({ class: css('_flex _aic _gap2') },
              Select({
                value: member.role,
                onChange: (e) => onRoleChange(member.id, e.target.value),
                options: roles,
                size: 'sm'
              }),
              Button({ variant: 'ghost', size: 'sm', onclick: () => onRemove(member.id) },
                icon('x', { size: '14' })
              )
            )
        )
      )
    ),
    // Pending invites
    pending.length > 0 ? div({ class: css('_flex _col _gap2 _pt4 _borderT') },
      span({ class: css('_textsm _fontmedium _fgmuted') }, 'Pending invitations'),
      ...pending.map(invite =>
        div({ class: css('_flex _aic _gap3 _py2 _opacity70') },
          div({ class: css('_w8 _h8 _rfull _bg[var(--surface-raised)] _flex _aic _jcc') },
            icon('mail', { size: '14', class: css('_fgmuted') })
          ),
          div({ class: css('_flex _col _flex1') },
            span({ class: css('_textsm') }, invite.email),
            span({ class: css('_textxs _fgmuted') }, `Invited as ${invite.role}`)
          ),
          Button({ variant: 'ghost', size: 'sm', onclick: () => onCancelInvite(invite.id) },
            'Cancel'
          )
        )
      )
    ) : null
  );
}

