function ShareModal({ document, members, pending, onInvite, onClose }) {
  const [activeTab, setActiveTab] = createSignal('invite');
  return Modal({ onClose },
    Tabs({ value: activeTab(), onChange: setActiveTab, items: ['invite', 'link', 'members'] }),
    activeTab() === 'invite' ? InviteForm({ onInvite }) :
    activeTab() === 'link' ? LinkSharing({ shareLink: document.shareLink }) :
    MembersList({ members, pending })
  );
}
